enum OptionType {
  STRING,
  NUMBER,
  BIGINT,
  BOOLEAN,
  SELECT,
  SLIDER,
  COMPONENT,
  CUSTOM,
}

const STRING = { type: OptionType.STRING };
const NUMBER = { type: OptionType.NUMBER };
const BIGINT = { type: OptionType.BIGINT };
const BOOLEAN = { type: OptionType.BOOLEAN };
const SELECT = { type: OptionType.SELECT };
const SLIDER = { type: OptionType.SLIDER };
